import { test, expect, Page } from '@playwright/test';

const BASE_URL = process.env.BASE_URL || 'http://localhost:3002';

// ─── Mock XML responses ───────────────────────────────────────────────────────

const MOCK_RESUME_XML = `<document type="resume">
  <header>
    <name>Alex Morgan</name>
    <contact>
      <email>alex.morgan@email.com</email>
      <phone>(416) 555-0182</phone>
      <location>Toronto, ON</location>
    </contact>
  </header>
  <summary>Senior Software Engineer with 7 years of experience building scalable web applications.</summary>
  <experience>
    <role>
      <title>Senior Software Engineer</title>
      <company>Shopify</company>
      <period>March 2021 – Present</period>
      <bullets>
        <bullet>Led migration of core checkout service from monolith to microservices</bullet>
      </bullets>
    </role>
  </experience>
  <education>
    <degree>Bachelor of Science, Computer Science</degree>
    <school>University of Waterloo</school>
    <year>2016</year>
  </education>
  <skills>JavaScript, TypeScript, Python, React, Node.js, PostgreSQL, AWS</skills>
</document>`;

const MOCK_LETTER_XML = `<document type="cover-letter">
  <header>
    <name>Jane Park</name>
    <contact>
      <email>jane.park@email.com</email>
      <location>Vancouver, BC</location>
    </contact>
  </header>
  <date>March 9, 2026</date>
  <recipient>
    <name>Hiring Manager</name>
    <company>Acme Technology</company>
    <address>San Francisco, CA</address>
  </recipient>
  <greeting>Dear Hiring Manager,</greeting>
  <body>
    <paragraph>I am writing to apply for the Product Designer position at Acme Technology.</paragraph>
    <paragraph>Thank you for your time and consideration.</paragraph>
  </body>
  <closing>Sincerely,</closing>
  <signature>Jane Park</signature>
</document>`;

// ─── Helpers ──────────────────────────────────────────────────────────────────

/**
 * Navigate to BASE_URL and wait for full hydration (including Nuxt 3 client-side
 * mounting) before the test body begins.
 */
async function gotoAndWait(page: Page): Promise<void> {
  await page.goto(BASE_URL);
  await page.waitForLoadState('networkidle');
  await page.locator('textarea').waitFor({ state: 'visible', timeout: 15_000 });
}

/**
 * Scope type-toggle buttons to the .type-selector container to avoid matching
 * the "Format My Resume" / "Format My Letter" UButton.
 */
function getResumeToggle(page: Page) {
  return page.locator('button.type-btn').filter({ hasText: 'Resume' });
}

function getLetterToggle(page: Page) {
  return page.locator('button.type-btn').filter({ hasText: 'Letter' });
}

async function hasActiveClass(button: ReturnType<typeof getResumeToggle>): Promise<boolean> {
  return button.evaluate(el => el.classList.contains('type-btn--active'));
}

// ─── FRG-217 Tests ────────────────────────────────────────────────────────────

// Test 1: Empty state shows sample buttons
test('FRG-217 / 1. Empty state shows "Try Resume Sample" and "Try Letter Sample" buttons', async ({ page }) => {
  await gotoAndWait(page);

  // The right panel should show the empty state with sample buttons
  await expect(page.getByText('Your formatted document will appear here.')).toBeVisible();

  const resumeSampleBtn = page.getByRole('button', { name: /try resume sample/i });
  const letterSampleBtn = page.getByRole('button', { name: /try letter sample/i });

  await expect(resumeSampleBtn, '"Try Resume Sample" button should be visible in empty state').toBeVisible();
  await expect(letterSampleBtn, '"Try Letter Sample" button should be visible in empty state').toBeVisible();

  // Both buttons should be enabled in the idle state
  await expect(resumeSampleBtn).toBeEnabled();
  await expect(letterSampleBtn).toBeEnabled();
});

// Test 2: Action bar shows sample links
test('FRG-217 / 2. Action bar shows "Try a sample: Resume · Letter" links', async ({ page }) => {
  await gotoAndWait(page);

  // "Try a sample:" label in action bar (use class selector to avoid matching the empty-state hint)
  await expect(page.locator('span.sample-label')).toBeVisible();

  // Resume and Letter sample links in action bar
  const resumeLink = page.locator('button.sample-link').filter({ hasText: /^Resume$/ });
  const letterLink = page.locator('button.sample-link').filter({ hasText: /^Letter$/ });
  const sepText = page.locator('.sample-sep');

  await expect(resumeLink, '"Resume" sample link should be visible in action bar').toBeVisible();
  await expect(letterLink, '"Letter" sample link should be visible in action bar').toBeVisible();
  await expect(sepText, 'Separator "·" should be visible between sample links').toBeVisible();
});

// Test 3: Resume sample loads, populates textarea, switches doc type, triggers format
test('FRG-217 / 3. Resume sample loads text, sets doc type to Resume, sends docType "resume" to API', async ({ page }) => {
  let capturedBody: Record<string, unknown> | null = null;

  await page.route('**/api/format', async route => {
    capturedBody = JSON.parse(route.request().postData() || '{}');
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ xml: MOCK_RESUME_XML, divergence: 0.01, documentType: 'resume' }),
    });
  });

  await gotoAndWait(page);

  // Click "Try Resume Sample" in the empty state panel
  const resumeSampleBtn = page.getByRole('button', { name: /try resume sample/i });
  await expect(resumeSampleBtn).toBeVisible();
  await resumeSampleBtn.click();

  // Textarea should now contain the sample resume text (Alex Morgan)
  const textarea = page.locator('textarea');
  await expect(async () => {
    const value = await textarea.inputValue();
    expect(value, 'Textarea should contain sample resume text').toContain('Alex Morgan');
  }).toPass({ timeout: 5_000 });

  // Doc type selector should switch to Resume (already default, but verify)
  const resumeBtn = getResumeToggle(page);
  expect(
    await hasActiveClass(resumeBtn),
    'Resume toggle should be active after loading resume sample',
  ).toBe(true);

  // Wait for formatting to complete (mocked)
  await expect(page.getByText('Your formatted document will appear here.')).not.toBeVisible({
    timeout: 15_000,
  });
  await expect(page.getByText('Preparing preview…')).not.toBeVisible({ timeout: 10_000 });

  // API request body should contain docType: "resume"
  expect(capturedBody, 'API request should have been made').not.toBeNull();
  expect(capturedBody!.docType, 'Request body should contain docType: "resume"').toBe('resume');

  // Formatted preview should show resume content (from mock XML)
  await expect(page.getByText('Alex Morgan', { exact: false })).toBeVisible({ timeout: 10_000 });
});

// Test 4: Letter sample loads, populates textarea, switches doc type, triggers format
test('FRG-217 / 4. Letter sample loads text, sets doc type to Letter, sends docType "letter" to API', async ({ page }) => {
  let capturedBody: Record<string, unknown> | null = null;

  await page.route('**/api/format', async route => {
    capturedBody = JSON.parse(route.request().postData() || '{}');
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ xml: MOCK_LETTER_XML, divergence: 0.01, documentType: 'cover-letter' }),
    });
  });

  await gotoAndWait(page);

  // Click "Try Letter Sample" in the empty state panel
  const letterSampleBtn = page.getByRole('button', { name: /try letter sample/i });
  await expect(letterSampleBtn).toBeVisible();
  await letterSampleBtn.click();

  // Textarea should now contain the sample letter text (Jane Park)
  const textarea = page.locator('textarea');
  await expect(async () => {
    const value = await textarea.inputValue();
    expect(value, 'Textarea should contain sample letter text').toContain('Jane Park');
  }).toPass({ timeout: 5_000 });

  // Doc type selector should switch to Letter
  const letterBtn = getLetterToggle(page);
  await expect(async () => {
    expect(
      await hasActiveClass(letterBtn),
      'Letter toggle should be active after loading letter sample',
    ).toBe(true);
  }).toPass({ timeout: 3_000 });

  // Wait for formatting to complete (mocked)
  await expect(page.getByText('Your formatted document will appear here.')).not.toBeVisible({
    timeout: 15_000,
  });
  await expect(page.getByText('Preparing preview…')).not.toBeVisible({ timeout: 10_000 });

  // API request body should contain docType: "letter"
  expect(capturedBody, 'API request should have been made').not.toBeNull();
  expect(capturedBody!.docType, 'Request body should contain docType: "letter"').toBe('letter');

  // Formatted preview should show letter content (from mock XML)
  const bodyText = await page.locator('body').innerText();
  expect(bodyText, 'Preview should contain sender name').toMatch(/Jane Park/);
  expect(bodyText, 'Preview should contain recipient company').toMatch(/Acme Technology/);
});

// Test 5: Buttons and links are disabled during formatting
test('FRG-217 / 5. Sample links are disabled while formatting is in progress', async ({ page }) => {
  // Intercept and delay the API for 10 seconds — enough time to verify the disabled state
  await page.route('**/api/format', async route => {
