import { test, expect, Page } from '@playwright/test';

const BASE_URL = process.env.BASE_URL || 'http://localhost:3000';

// ─── Sample content ───────────────────────────────────────────────────────────

const RESUME_TEXT = `Alex Rivera
alex.rivera@email.com · (555) 123-4567 · San Francisco, CA

SUMMARY
Full-stack software engineer with 7 years of experience building scalable web applications.

EXPERIENCE
Senior Software Engineer — Acme Corp (2021–Present)
• Led development of a microservices architecture serving 2M+ daily active users
• Reduced API latency by 40% through caching and query optimization

EDUCATION
B.S. Computer Science — University of California, Berkeley (2019)

SKILLS
JavaScript, TypeScript, React, Node.js, Docker, AWS`.trim();

const LETTER_TEXT = `Alex Rivera
alex.rivera@email.com · San Francisco, CA

March 4, 2026

Hiring Manager
TechVision Inc.
123 Innovation Drive
San Francisco, CA 94102

Dear Hiring Manager,

I am writing to express my strong interest in the Senior Software Engineer position at TechVision Inc.
With seven years of experience building high-performance web applications, I am confident I would
make a valuable addition to your team.

Thank you for considering my application.

Sincerely,
Alex Rivera`.trim();

// ─── Mock XML responses ───────────────────────────────────────────────────────

const MOCK_RESUME_XML = `<document type="resume">
  <header>
    <name>Alex Rivera</name>
    <contact>
      <email>alex.rivera@email.com</email>
      <phone>(555) 123-4567</phone>
      <location>San Francisco, CA</location>
    </contact>
  </header>
  <summary>Full-stack software engineer with 7 years of experience building scalable web applications.</summary>
  <experience>
    <role>
      <title>Senior Software Engineer</title>
      <company>Acme Corp</company>
      <period>2021–Present</period>
      <bullets>
        <bullet>Led development of a microservices architecture serving 2M+ daily active users</bullet>
        <bullet>Reduced API latency by 40% through caching and query optimization</bullet>
      </bullets>
    </role>
  </experience>
  <education>
    <degree>B.S. Computer Science</degree>
    <school>University of California, Berkeley</school>
    <year>2019</year>
  </education>
  <skills>JavaScript, TypeScript, React, Node.js, Docker, AWS</skills>
</document>`;

const MOCK_LETTER_XML = `<document type="cover-letter">
  <header>
    <name>Alex Rivera</name>
    <contact>
      <email>alex.rivera@email.com</email>
      <location>San Francisco, CA</location>
    </contact>
  </header>
  <date>March 4, 2026</date>
  <recipient>
    <name>Hiring Manager</name>
    <company>TechVision Inc.</company>
    <address>San Francisco, CA 94102</address>
  </recipient>
  <greeting>Dear Hiring Manager,</greeting>
  <body>
    <paragraph>I am writing to express my strong interest in the Senior Software Engineer position at TechVision Inc. With seven years of experience building high-performance web applications, I am confident I would make a valuable addition to your team.</paragraph>
    <paragraph>Thank you for considering my application.</paragraph>
  </body>
  <closing>Sincerely,</closing>
  <signature>Alex Rivera</signature>
</document>`;

// ─── Helpers ──────────────────────────────────────────────────────────────────

/**
 * Navigate to BASE_URL and wait for full hydration (including Nuxt 3 client-side
 * mounting) before the test body begins.
 */
async function gotoAndWait(page: Page): Promise<void> {
  await page.goto(BASE_URL);
  await page.waitForLoadState('networkidle');
  // Ensure the textarea is visible — confirms Vue has mounted
  await page.locator('textarea').waitFor({ state: 'visible', timeout: 15_000 });
}

/**
 * Reliably fill a textarea and wait for Vue's reactive model to update.
 * Uses click + fill + value verification to avoid intermittent fill() issues.
 */
async function fillTextarea(page: Page, text: string): Promise<void> {
  const textarea = page.locator('textarea');
  await textarea.click();
  await textarea.fill(text);
  await page.waitForTimeout(300);
  // Verify the value was actually set; retry once if needed
  const value = await textarea.inputValue();
  if (value.length < 10 && text.length > 10) {
    await textarea.click();
    await textarea.fill(text);
    await page.waitForTimeout(500);
  }
}

/**
 * Scope type-toggle buttons to the .type-selector container to avoid matching
 * the "Format My Resume" / "Format My Letter" UButton, which also contains
 * the words "Resume" and "Letter" in its accessible name.
 */
function getResumeToggle(page: Page) {
  return page.locator('button.type-btn').filter({ hasText: 'Resume' });
}

function getLetterToggle(page: Page) {
  return page.locator('button.type-btn').filter({ hasText: 'Letter' });
}

async function hasActiveClass(button: ReturnType<typeof getResumeToggle>): Promise<boolean> {
  return button.evaluate(el => el.classList.contains('type-btn--active'));
}

// ─── FRG-216 Tests ────────────────────────────────────────────────────────────

// Test 1: Doc type selector renders
test('FRG-216 / 1. Doc type selector renders with Resume active by default', async ({ page }) => {
  await gotoAndWait(page);

  const resumeBtn = getResumeToggle(page);
  const letterBtn = getLetterToggle(page);

  // Both toggle buttons must exist
  await expect(resumeBtn).toBeVisible();
  await expect(letterBtn).toBeVisible();

  // Resume is active by default
  const resumeIsActive = await hasActiveClass(resumeBtn);
  expect(resumeIsActive, 'Resume button should have active styling by default').toBe(true);

  const letterIsActive = await hasActiveClass(letterBtn);
  expect(letterIsActive, 'Letter button should NOT be active by default').toBe(false);

  // Format button label reflects Resume selection
  await expect(page.getByRole('button', { name: /format my resume/i })).toBeVisible();
});

// Test 2: Toggle switches to Letter
test('FRG-216 / 2. Toggle switches to Letter — button and label update', async ({ page }) => {
  await gotoAndWait(page);

  const resumeBtn = getResumeToggle(page);
  const letterBtn = getLetterToggle(page);

  // Click Letter toggle
  await letterBtn.click();
  await page.waitForTimeout(300); // allow Vue reactivity

  // Letter should become active, Resume should not
  const letterIsActive = await hasActiveClass(letterBtn);
  expect(letterIsActive, 'Letter button should have active styling after click').toBe(true);

  const resumeIsActive = await hasActiveClass(resumeBtn);
  expect(resumeIsActive, 'Resume button should lose active styling').toBe(false);

  // Format button label must change to Letter
  await expect(page.getByRole('button', { name: /format my letter/i })).toBeVisible({ timeout: 5_000 });
  await expect(page.getByRole('button', { name: /format my resume/i })).not.toBeVisible();
});

// Test 3: Toggle switches back to Resume
test('FRG-216 / 3. Toggle switches back to Resume', async ({ page }) => {
  await gotoAndWait(page);

  const resumeBtn = getResumeToggle(page);
  const letterBtn = getLetterToggle(page);

  // Switch to Letter then back to Resume
  await letterBtn.click();
  await page.waitForTimeout(300);
  await resumeBtn.click();
  await page.waitForTimeout(300);

  // Resume should be active again
  const resumeIsActive = await hasActiveClass(resumeBtn);
  expect(resumeIsActive, 'Resume button should be active after switching back').toBe(true);

  const letterIsActive = await hasActiveClass(letterBtn);
  expect(letterIsActive, 'Letter button should be inactive after switching back').toBe(false);

  // Format button label must revert
  await expect(page.getByRole('button', { name: /format my resume/i })).toBeVisible({ timeout: 5_000 });
  await expect(page.getByRole('button', { name: /format my letter/i })).not.toBeVisible();
});

// Test 4: Type toggle buttons disabled during formatting
test('FRG-216 / 4. Type toggle buttons are disabled while formatting is in progress', async ({ page }) => {
  // Intercept and delay the API for 10 seconds — enough time to verify the disabled state
  await page.route('**/api/format', async route => {
    await new Promise(r => setTimeout(r, 10_000));
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ xml: MOCK_RESUME_XML, divergence: 0.01, documentType: 'resume' }),
    });
  });

  await gotoAndWait(page);
  await fillTextarea(page, RESUME_TEXT);

  const formatBtn = page.getByRole('button', { name: /format my resume/i });
  await expect(formatBtn).toBeEnabled({ timeout: 5_000 });
  await formatBtn.click();

  // Both type-toggle buttons must be disabled while API request is in flight
  const resumeBtn = getResumeToggle(page);
  const letterBtn = getLetterToggle(page);

  await expect(resumeBtn, 'Resume toggle should be disabled during formatting').toBeDisabled({ timeout: 5_000 });
  await expect(letterBtn, 'Letter toggle should be disabled during formatting').toBeDisabled({ timeout: 5_000 });
});

// Test 5: Resume formatting sends correct docType and shows resume XML elements
test('FRG-216 / 5. Resume formatting — correct docType sent, resume XML in preview', async ({ page }) => {
  let capturedDocType: string | null = null;

  await page.route('**/api/format', async route => {
    const body = JSON.parse(route.request().postData() || '{}');
    capturedDocType = body.docType;
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ xml: MOCK_RESUME_XML, divergence: 0.02, documentType: 'resume' }),
    });
  });

  await gotoAndWait(page);

  // Resume is selected by default
  const resumeBtn = getResumeToggle(page);
  expect(await hasActiveClass(resumeBtn), 'Resume toggle should be active by default').toBe(true);

  await fillTextarea(page, RESUME_TEXT);
  const formatBtn = page.getByRole('button', { name: /format my resume/i });
  await expect(formatBtn).toBeEnabled({ timeout: 5_000 });
  await formatBtn.click();

  // Wait for preview to replace the placeholder
  await expect(page.getByText('Your formatted document will appear here.')).not.toBeVisible({ timeout: 15_000 });

  // docType sent in request must be 'resume'
  expect(capturedDocType, 'Request body should contain docType: "resume"').toBe('resume');

  // Preview should render content from the mocked resume XML
  await expect(page.getByText('Alex Rivera', { exact: false })).toBeVisible();
  await expect(page.getByText('Acme Corp', { exact: false })).toBeVisible();
});

// Test 6: Letter formatting sends correct docType and shows letter XML elements
test('FRG-216 / 6. Letter formatting — correct docType sent, letter XML in preview', async ({ page }) => {
  let capturedDocType: string | null = null;

  await page.route('**/api/format', async route => {
    const body = JSON.parse(route.request().postData() || '{}');
    capturedDocType = body.docType;
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ xml: MOCK_LETTER_XML, divergence: 0.02, documentType: 'cover-letter' }),
    });
  });

  await gotoAndWait(page);

  // Switch to Letter
  const letterBtn = getLetterToggle(page);
  await letterBtn.click();
  await page.waitForTimeout(300);
  await expect(page.getByRole('button', { name: /format my letter/i })).toBeVisible({ timeout: 5_000 });

  await fillTextarea(page, LETTER_TEXT);
  await page.getByRole('button', { name: /format my letter/i }).click();

  // Wait for the initial placeholder to go away, then for the async DOMPurify
  // sanitization step ("Preparing preview…") to also complete.
  await expect(page.getByText('Your formatted document will appear here.')).not.toBeVisible({ timeout: 15_000 });
  await expect(page.getByText('Preparing preview…')).not.toBeVisible({ timeout: 15_000 });

  // docType sent in request must be 'letter'
  expect(capturedDocType, 'Request body should contain docType: "letter"').toBe('letter');

  // Verify letter-specific content in the rendered preview.
  // Some strings appear in multiple XML nodes (name/signature, company/paragraph)
  // so we assert on the full body text rather than individual locators.
  const bodyText = await page.locator('body').innerText();
  expect(bodyText, 'Preview should contain sender name').toMatch(/Alex Rivera/);
  expect(bodyText, 'Preview should contain recipient company').toMatch(/TechVision/);
  expect(bodyText, 'Preview should contain greeting').toMatch(/Dear Hiring Manager/i);
  expect(bodyText, 'Preview should contain closing').toMatch(/Sincerely/i);
});

