function getEditXmlButton(page: Page) {
  return page.getByRole('button', { name: /edit xml/i });
}

/** The "← Back to text" control (button or link) shown in XML mode. */
function getBackToTextControl(page: Page) {
  return page
    .getByRole('button', { name: /back to text/i })
    .or(page.getByRole('link', { name: /back to text/i }))
    .or(page.getByText(/←\s*back to text/i));
