 * Find the textarea that contains raw XML (the XML editor, not the text input).
 * Waits up to 5 s for at least one textarea to hold XML content.
 */
async function getXmlTextarea(page: Page) {
  await page.waitForFunction(
    () => {
      const tas = Array.from(document.querySelectorAll('textarea'));
      return tas.some(ta => ta.value.trimStart().startsWith('<'));
    },
    undefined,
    { timeout: 10_000 },
  );
  const all = await page.locator('textarea').all();
  for (const ta of all) {
    const val = await ta.inputValue();
    if (val.trimStart().startsWith('<')) return ta;
  }
  // Fallback — should not normally be reached
  return page.locator('textarea').first();
}

/**
 * Mock the /api/format endpoint, navigate, fill the textarea, click Format,
 * and wait for the preview.  Returns after the preview is rendered.
 */
async function formatWithMock(
  page: Page,
  mockXml: string = MOCK_RESUME_XML,
): Promise<void> {
  await page.route('**/api/format', async route => {
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ xml: mockXml, divergence: 0.01, documentType: 'resume' }),
    });
  });
  await gotoAndWait(page);
  await fillTextarea(page, RESUME_TEXT);
  const formatBtn = page.getByRole('button', { name: /format my resume/i });
  await expect(formatBtn).toBeEnabled({ timeout: 5_000 });
  await formatBtn.click();
  await waitForPreview(page);
}

