  await editXmlBtn.click();

  // Confirm XML mode is active
  const xmlTextarea = await getXmlTextarea(page);
  await expect(xmlTextarea).toBeVisible();

  // Click Back to text
  const backLink = getBackToTextControl(page);
  await expect(backLink, '"← Back to text" control should be visible in XML mode').toBeVisible({
    timeout: 5_000,
  });
