  // The main text textarea must become visible again
  const mainTextarea = page.locator('textarea').first();
  await expect(mainTextarea, 'Main text textarea should be visible after "Back to text"').toBeVisible({
    timeout: 5_000,
  });

  // The original resume text should be present in the textarea
  const textValue = await mainTextarea.inputValue();
  expect(textValue.length, 'Text textarea should still contain the original input').toBeGreaterThan(50);

  // The XML textarea should no longer be visible
  const xmlAfter = await page.locator('textarea').all();
  let xmlVisible = false;
  for (const ta of xmlAfter) {
    const val = await ta.inputValue();
    if (val.trimStart().startsWith('<') && await ta.isVisible()) {
      xmlVisible = true;
    }
  }
  expect(xmlVisible, 'XML textarea should not be visible after "Back to text"').toBe(false);
});

// ── 8. Re-format with AI ─────────────────────────────────────────────────────

test('FRG-215 / 8. "Re-format with AI" in XML mode re-runs formatting', async ({ page }) => {
  let apiCallCount = 0;

  await page.route('**/api/format', async route => {
    apiCallCount++;
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ xml: MOCK_RESUME_XML, divergence: 0.01, documentType: 'resume' }),
    });
  });

  await gotoAndWait(page);
  await fillTextarea(page, RESUME_TEXT);

  // First format
  const formatBtn = page.getByRole('button', { name: /format my resume/i });
  await expect(formatBtn).toBeEnabled({ timeout: 5_000 });
  await formatBtn.click();
  await waitForPreview(page);

  const firstCallCount = apiCallCount;
  expect(firstCallCount, 'API should have been called once after first format').toBe(1);

  // Enter XML mode
  const editXmlBtn = getEditXmlButton(page);
  await expect(editXmlBtn).toBeVisible({ timeout: 5_000 });
  await editXmlBtn.click();

  const xmlTextarea = await getXmlTextarea(page);
  await expect(xmlTextarea).toBeVisible();

