test('FRG-215 / 2. "Edit XML" button appears after formatting', async ({ page }) => {
  await formatWithMock(page);

  const editXmlBtn = getEditXmlButton(page);
  await expect(editXmlBtn, '"Edit XML" button should be visible after formatting completes').toBeVisible({
    timeout: 5_000,
  });
  await expect(editXmlBtn).toBeEnabled();
});

// ── 3. Enter XML edit mode ───────────────────────────────────────────────────

test('FRG-215 / 3. Clicking "Edit XML" shows XML textarea and hides text input', async ({ page }) => {
  await formatWithMock(page);

  // Click the Edit XML button
  const editXmlBtn = getEditXmlButton(page);
  await expect(editXmlBtn).toBeVisible({ timeout: 5_000 });
  await editXmlBtn.click();

  // An XML textarea must now be visible
  const xmlTextarea = await getXmlTextarea(page);
  await expect(xmlTextarea, 'XML textarea should be visible after clicking Edit XML').toBeVisible({
    timeout: 5_000,
  });

  // The XML textarea must contain the generated XML
  const xmlContent = await xmlTextarea.inputValue();
  expect(xmlContent.trim(), 'XML textarea should contain the generated XML').toMatch(/^<document/i);
});

// ── 4. XML content fidelity ──────────────────────────────────────────────────

test('FRG-215 / 4. XML textarea displays the generated XML with correct content', async ({ page }) => {
  await formatWithMock(page);

  const editXmlBtn = getEditXmlButton(page);
  await expect(editXmlBtn).toBeVisible({ timeout: 5_000 });
  await editXmlBtn.click();

  const xmlTextarea = await getXmlTextarea(page);
  const xmlContent = await xmlTextarea.inputValue();

  // The XML must contain the name from the mock response
  expect(xmlContent, 'XML should contain "Alex Rivera"').toContain('Alex Rivera');
  // The XML must contain the employer from the mock response
  expect(xmlContent, 'XML should contain "Acme Corp"').toContain('Acme Corp');
  // Basic XML structure
  expect(xmlContent, 'XML should have a closing </document> tag').toContain('</document>');
});

// ── 5. Monospace font ────────────────────────────────────────────────────────

test('FRG-215 / 5. XML textarea uses a monospace font', async ({ page }) => {
  await formatWithMock(page);

  const editXmlBtn = getEditXmlButton(page);
  await expect(editXmlBtn).toBeVisible({ timeout: 5_000 });
  await editXmlBtn.click();

  const xmlTextarea = await getXmlTextarea(page);

  // Check computed font-family contains a monospace indicator
  const fontFamily = await xmlTextarea.evaluate(
    el => window.getComputedStyle(el).fontFamily.toLowerCase(),
  );
  const isMonospace =
    fontFamily.includes('mono') ||
    fontFamily.includes('courier') ||
    fontFamily.includes('consolas') ||
    fontFamily.includes('menlo') ||
    fontFamily.includes('source code') ||
    fontFamily.includes('fira code');

  expect(isMonospace, `XML textarea font-family "${fontFamily}" should be monospace`).toBe(true);
});

// ── 6. Real-time preview update on XML edit ──────────────────────────────────

test('FRG-215 / 6. Editing the XML updates the preview in real-time', async ({ page }) => {
  await formatWithMock(page);

  const editXmlBtn = getEditXmlButton(page);
  await expect(editXmlBtn).toBeVisible({ timeout: 5_000 });
  await editXmlBtn.click();

  const xmlTextarea = await getXmlTextarea(page);
  const originalXml = await xmlTextarea.inputValue();

  // Replace the name in the XML to a unique test value
  const modifiedXml = originalXml.replace(/Alex Rivera/g, 'Taylor Playwright');
  await xmlTextarea.fill(modifiedXml);
  await page.waitForTimeout(500); // allow debounce / reactive update

  // The preview pane should reflect the edited name
  const bodyText = await page.locator('body').innerText();
  expect(bodyText, 'Preview should update with the edited name "Taylor Playwright"').toContain(
    'Taylor Playwright',
  );
  expect(bodyText, 'Original name "Alex Rivera" should no longer appear in preview').not.toContain(
    'Alex Rivera',
  );
});

// ── 7. Back to text ──────────────────────────────────────────────────────────

test('FRG-215 / 7. "← Back to text" returns to the text input view', async ({ page }) => {
  await formatWithMock(page);

  const editXmlBtn = getEditXmlButton(page);
  await expect(editXmlBtn).toBeVisible({ timeout: 5_000 });
  await editXmlBtn.click();

  // Confirm XML mode is active
  const xmlTextarea = await getXmlTextarea(page);
  await expect(xmlTextarea).toBeVisible();

  // Click Back to text
  const backLink = getBackToTextControl(page);
  await expect(backLink, '"← Back to text" control should be visible in XML mode').toBeVisible({
    timeout: 5_000,
  });
  await backLink.click();
  await page.waitForTimeout(300);

  // The main text textarea must become visible again
  const mainTextarea = page.locator('textarea').first();
  await expect(mainTextarea, 'Main text textarea should be visible after "Back to text"').toBeVisible({
    timeout: 5_000,
  });

  // The original resume text should be present in the textarea
  const textValue = await mainTextarea.inputValue();
  expect(textValue.length, 'Text textarea should still contain the original input').toBeGreaterThan(50);

  // The XML textarea should no longer be visible
  const xmlAfter = await page.locator('textarea').all();
  let xmlVisible = false;
  for (const ta of xmlAfter) {
    const val = await ta.inputValue();
    if (val.trimStart().startsWith('<') && await ta.isVisible()) {
      xmlVisible = true;
    }
  }
  expect(xmlVisible, 'XML textarea should not be visible after "Back to text"').toBe(false);
});

// ── 8. Re-format with AI ─────────────────────────────────────────────────────

test('FRG-215 / 8. "Re-format with AI" in XML mode re-runs formatting', async ({ page }) => {
  let apiCallCount = 0;

  await page.route('**/api/format', async route => {
    apiCallCount++;
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ xml: MOCK_RESUME_XML, divergence: 0.01, documentType: 'resume' }),
    });
  });

  await gotoAndWait(page);
  await fillTextarea(page, RESUME_TEXT);

  // First format
  const formatBtn = page.getByRole('button', { name: /format my resume/i });
  await expect(formatBtn).toBeEnabled({ timeout: 5_000 });
  await formatBtn.click();
  await waitForPreview(page);

  const firstCallCount = apiCallCount;
  expect(firstCallCount, 'API should have been called once after first format').toBe(1);

  // Enter XML mode
  const editXmlBtn = getEditXmlButton(page);
  await expect(editXmlBtn).toBeVisible({ timeout: 5_000 });
  await editXmlBtn.click();

  const xmlTextarea = await getXmlTextarea(page);
  await expect(xmlTextarea).toBeVisible();

  // Re-format with AI button should be present in XML mode
  const refornatBtn = getReformatButton(page);
  await expect(refornatBtn, '"Re-format with AI" button should be visible in XML mode').toBeVisible({
    timeout: 5_000,
  });
  await refornatBtn.click();

  // A second API call should have been made
  await page.waitForFunction(
    (count) => (window as any)._apiCount >= count,
    undefined,
    { timeout: 10_000 },
  ).catch(() => {/* fallback: check count directly */});

  await page.waitForTimeout(1_000); // allow the request to land

  expect(apiCallCount, 'A second API call should occur after Re-format with AI').toBeGreaterThan(
    firstCallCount,
  );

  // After re-formatting, we should be back in text/preview mode (not XML mode)
  await waitForPreview(page);

  // XML textarea should no longer be the active view
  const mainTextarea = page.locator('textarea').first();
  await expect(mainTextarea).toBeVisible({ timeout: 5_000 });
});

// ── 9. Re-format with AI — exits XML mode ────────────────────────────────────

test('FRG-215 / 9. After "Re-format with AI" the text input view is restored', async ({ page }) => {
  await formatWithMock(page);

  // Enter XML mode
  const editXmlBtn = getEditXmlButton(page);
  await expect(editXmlBtn).toBeVisible({ timeout: 5_000 });
  await editXmlBtn.click();

  const xmlTextarea = await getXmlTextarea(page);
  await expect(xmlTextarea).toBeVisible();

  // Click Re-format with AI
  const refornatBtn = getReformatButton(page);
  await expect(refornatBtn).toBeVisible({ timeout: 5_000 });
  await refornatBtn.click();
  await page.waitForTimeout(500);

  // The main textarea should become visible
  const mainTextarea = page.locator('textarea').first();
  await expect(mainTextarea, 'Text input should be visible after Re-format').toBeVisible({
    timeout: 10_000,
  });

  // The XML textarea should no longer be shown
  const xmlAfter = await page.locator('textarea').all();
  let xmlVisible = false;
  for (const ta of xmlAfter) {
    const val = await ta.inputValue().catch(() => '');
    if (val.trimStart().startsWith('<') && (await ta.isVisible())) {
      xmlVisible = true;
    }
  }
  expect(xmlVisible, 'XML textarea should be dismissed after Re-format with AI').toBe(false);
});

// ── 10. Full flow — Try Sample → Format → Edit XML ───────────────────────────

test('FRG-215 / 10. Full flow: Try Sample → Format → Edit XML → verify content', async ({ page }) => {
  let capturedXml = '';

  await page.route('**/api/format', async route => {
    capturedXml = MOCK_RESUME_XML;
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ xml: MOCK_RESUME_XML, divergence: 0.01, documentType: 'resume' }),
    });
  });

  await gotoAndWait(page);

  // Try the Resume sample button (action bar or empty-state)
  const sampleBtn = page
    .getByRole('button', { name: /try resume sample/i })
    .or(page.locator('button.sample-link').filter({ hasText: /^Resume$/ }))
    .or(page.getByRole('button', { name: /sample/i }).first());

  const hasSampleBtn = await sampleBtn.isVisible({ timeout: 3_000 }).catch(() => false);

  if (hasSampleBtn) {
    await sampleBtn.click();
    // Textarea should populate
    await expect(async () => {
      const val = await page.locator('textarea').first().inputValue();
      expect(val.length, 'Textarea should be populated by sample').toBeGreaterThan(50);
    }).toPass({ timeout: 5_000 });
  } else {
    // Fallback: manually fill the textarea
    console.log('[FRG-215 / 10] No sample button found — filling textarea manually');
    await fillTextarea(page, RESUME_TEXT);
  }

  // Format the document
  const formatBtn = page.getByRole('button', { name: /format my resume/i });
  await expect(formatBtn).toBeEnabled({ timeout: 5_000 });
  await formatBtn.click();
  await waitForPreview(page);

  // "Edit XML" must appear after formatting
  const editXmlBtn = getEditXmlButton(page);
  await expect(editXmlBtn, '"Edit XML" should appear after formatting a sample').toBeVisible({
    timeout: 5_000,
  });

  // Enter XML edit mode
  await editXmlBtn.click();

  // XML textarea must contain the generated XML
  const xmlTextarea = await getXmlTextarea(page);
  const xmlContent = await xmlTextarea.inputValue();
  expect(xmlContent.trim(), 'XML textarea should contain the XML that was generated').toMatch(
    /^<document/i,
  );
  expect(xmlContent, 'XML should contain the formatted resume content').toContain('Alex Rivera');
});

// ── 11. "Edit XML" button not present before formatting (explicit — short input) ──

test('FRG-215 / 11. "Edit XML" button absent when textarea has content but no format has run', async ({ page }) => {
  await gotoAndWait(page);

  // Type some content — enough to enable the Format button — but do not click Format
  await fillTextarea(page, RESUME_TEXT);

  const formatBtn = page.getByRole('button', { name: /format my resume/i });
  await expect(formatBtn).toBeEnabled({ timeout: 5_000 });

  // "Edit XML" must still not appear
  const editXmlBtn = getEditXmlButton(page);
  const isVisible = await editXmlBtn.isVisible().catch(() => false);
  expect(
    isVisible,
    '"Edit XML" button should NOT be visible when content is typed but formatting has not run',
  ).toBe(false);
});

