import { test, expect, Page } from '@playwright/test';

/**
 * FRG-215 — View / Edit XML
 *
 * Feature: after AI formatting an "Edit XML" button appears next to the Format
 * button.  Clicking it reveals the raw XML in an editable textarea (monospace).
 * Editing the XML updates the preview in real-time.  A "← Back to text" control
 * returns to the original text-input view.  A "Re-format with AI" button inside
 * XML mode clears XML, restores the text input, and re-runs AI formatting.
 *
 * Target deployment (set via BASE_URL env var):
 *   https://ohmydoc-using-claude-c-git-6204d7-kimwongwwk-gmailcoms-projects.vercel.app
 *
 * Note: most tests use page.route() to mock /api/format so they do not require
 * a live AI API key — only the OhMyDoc app HTML needs to load.
 * All tests that mock the API follow the same pattern as FRG-216 / FRG-217.
 */

const BASE_URL = process.env.BASE_URL || 'http://localhost:3000';

// ─── Mock XML ────────────────────────────────────────────────────────────────

const MOCK_RESUME_XML = `<document type="resume">
  <header>
    <name>Alex Rivera</name>
    <contact>
      <email>alex.rivera@email.com</email>
      <phone>(555) 123-4567</phone>
      <location>San Francisco, CA</location>
    </contact>
  </header>
  <summary>Full-stack software engineer with 7 years of experience building scalable web applications.</summary>
  <experience>
    <role>
      <title>Senior Software Engineer</title>
      <company>Acme Corp</company>
      <period>2021–Present</period>
      <bullets>
        <bullet>Led microservices migration serving 2M+ daily active users</bullet>
        <bullet>Reduced API latency by 40% through caching and query optimisation</bullet>
      </bullets>
    </role>
  </experience>
  <education>
    <degree>B.S. Computer Science</degree>
    <school>University of California, Berkeley</school>
    <year>2019</year>
  </education>
  <skills>JavaScript, TypeScript, React, Node.js, Docker, AWS</skills>
</document>`;

const RESUME_TEXT = `Alex Rivera
alex.rivera@email.com · (555) 123-4567 · San Francisco, CA

SUMMARY
Full-stack software engineer with 7 years of experience building scalable web applications.

EXPERIENCE
Senior Software Engineer — Acme Corp (2021–Present)
• Led microservices migration serving 2M+ daily active users
• Reduced API latency by 40% through caching and query optimisation

EDUCATION
B.S. Computer Science — University of California, Berkeley (2019)

SKILLS
JavaScript, TypeScript, React, Node.js, Docker, AWS`.trim();

// ─── Helpers ─────────────────────────────────────────────────────────────────

/** Navigate to BASE_URL and wait for full Vue/Nuxt hydration. */
async function gotoAndWait(page: Page): Promise<void> {
  await page.goto(BASE_URL);
  await page.waitForLoadState('networkidle');
  await page.locator('textarea').first().waitFor({ state: 'visible', timeout: 15_000 });
}

/** Reliably fill a textarea and wait for Vue reactivity. */
async function fillTextarea(page: Page, text: string): Promise<void> {
  const textarea = page.locator('textarea').first();
  await textarea.click();
  await textarea.fill(text);
  await page.waitForTimeout(300);
  const value = await textarea.inputValue();
  if (value.length < 10 && text.length > 10) {
    await textarea.click();
    await textarea.fill(text);
    await page.waitForTimeout(500);
  }
}

/** Wait for the AI formatting placeholder to disappear (preview rendered). */
async function waitForPreview(page: Page): Promise<void> {
  await expect(
    page.getByText('Your formatted document will appear here.'),
  ).not.toBeVisible({ timeout: 15_000 });
  // Dismiss any transient "Preparing preview…" message
  await page
    .getByText(/preparing preview/i)
    .waitFor({ state: 'hidden', timeout: 10_000 })
    .catch(() => {/* element may never appear — that's fine */});
}

/** The "Edit XML" button that appears in the action bar after formatting. */
function getEditXmlButton(page: Page) {
  return page.getByRole('button', { name: /edit xml/i });
}

/** The "← Back to text" control (button or link) shown in XML mode. */
function getBackToTextControl(page: Page) {
  return page
    .getByRole('button', { name: /back to text/i })
    .or(page.getByRole('link', { name: /back to text/i }))
    .or(page.getByText(/←\s*back to text/i));
}

/** The "Re-format with AI" button shown inside XML mode. */
function getReformatButton(page: Page) {
  return page.getByRole('button', { name: /re-format with ai/i });
}

/**
 * Find the textarea that contains raw XML (the XML editor, not the text input).
 * Waits up to 5 s for at least one textarea to hold XML content.
 */
async function getXmlTextarea(page: Page) {
  await page.waitForFunction(
    () => {
      const tas = Array.from(document.querySelectorAll('textarea'));
      return tas.some(ta => ta.value.trimStart().startsWith('<'));
    },
    undefined,
    { timeout: 10_000 },
  );
  const all = await page.locator('textarea').all();
  for (const ta of all) {
    const val = await ta.inputValue();
    if (val.trimStart().startsWith('<')) return ta;
  }
  // Fallback — should not normally be reached
  return page.locator('textarea').first();
}

/**
 * Mock the /api/format endpoint, navigate, fill the textarea, click Format,
 * and wait for the preview.  Returns after the preview is rendered.
 */
async function formatWithMock(
  page: Page,
  mockXml: string = MOCK_RESUME_XML,
): Promise<void> {
  await page.route('**/api/format', async route => {
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ xml: mockXml, divergence: 0.01, documentType: 'resume' }),
    });
  });
  await gotoAndWait(page);
  await fillTextarea(page, RESUME_TEXT);
  const formatBtn = page.getByRole('button', { name: /format my resume/i });
  await expect(formatBtn).toBeEnabled({ timeout: 5_000 });
  await formatBtn.click();
  await waitForPreview(page);
}

